                fontSize = 15.sp)
            Icon(Icons.Filled.KeyboardArrowDown, null,
                modifier = Modifier.rotate(rotation))
        }
        AnimatedVisibility(visible = expanded) {
            Box(Modifier.padding(start = 16.dp, end = 16.dp, bottom = 16.dp)) {
                content()
            }
        }
    }
