/** Horizontal multi-step indicator for wizards / checkout. */
@Composable
fun StepProgress(
    steps: List<String>,
    currentStep: Int,
    modifier: Modifier = Modifier,
) {
    val scheme = MaterialTheme.colorScheme
    Row(modifier, verticalAlignment = Alignment.Top) {
